 218→const attachUserInteractionFlags = async (journals, userId) => {
 219→    if(!Array.isArray(journals) || journals.length === 0){
 220→        return [];
 221→    }
 222→
 223→    if(!userId){
 224→        return journals.map((journal) => ({
 225→            ...journal,
 226→            has_liked: false,
 227→            has_bookmarked: false
 228→        }));
 229→    }
 230→
 231→    const journalIds = journals.map((journal) => journal.id);
 232→
 233→    const [userLikes, userBookmarks] = await Promise.all([
 234→        supabase
 235→            .from('likes')
 236→            .select('journal_id')
 237→            .in('journal_id', journalIds)
 238→            .eq('user_id', userId),
 239→        supabase
 240→            .from('bookmarks')
 241→            .select('journal_id')
 242→            .in('journal_id', journalIds)
 243→            .eq('user_id', userId)
 244→    ]);
 245→
 246→    const {data: userLikesResult, error: errorUserLikeResult} = userLikes;
 247→    const {data: userBookmarksResult, error: errorUserBookmarksResult} = userBookmarks;
 248→
 249→    if(errorUserLikeResult || errorUserBookmarksResult){
 250→        console.error('supabase error while fetching journal interactions:', errorUserLikeResult?.message || errorUserBookmarksResult?.message);
 251→        throw {status: 500, error: 'supabase error on fetching user likes or user bookmarks'};
 252→    }
 253→
 254→    const userHasLikedSet = new Set(userLikesResult?.map((journal) => journal.journal_id) || []);
 255→    const userHasBookmarkedSet = new Set(userBookmarksResult?.map((journal) => journal.journal_id) || []);
