 546→export const getUniversePostsService = async(minX, maxX, minY, maxY, limit = UNIVERSE_POST_LIMIT_DEFAULT) => {
 547→    const parsedMinX = parseFiniteNumber(minX, 'minX');
 548→    const parsedMaxX = parseFiniteNumber(maxX, 'maxX');
 549→    const parsedMinY = parseFiniteNumber(minY, 'minY');
 550→    const parsedMaxY = parseFiniteNumber(maxY, 'maxY');
 551→    const parsedLimit = Number(limit);
 552→
 553→    if(parsedMinX > parsedMaxX){
 554→        throw {status: 400, error: 'minX should be less than or equal to maxX'};
 555→    }
 556→
 557→    if(parsedMinY > parsedMaxY){
 558→        throw {status: 400, error: 'minY should be less than or equal to maxY'};
 559→    }
 560→
 561→    if(!Number.isInteger(parsedLimit) || parsedLimit < 1 || parsedLimit > UNIVERSE_POST_LIMIT_MAX){
 562→        throw {status: 400, error: `limit should be an integer between 1 and ${UNIVERSE_POST_LIMIT_MAX}`};
 563→    }
 564→
 565→    let posts = [];
 566→    let usedFallback = false;
 567→
 568→    try {
 569→        posts = await loadUniversePostsViaRpc(parsedMinX, parsedMaxX, parsedMinY, parsedMaxY, parsedLimit);
 570→    } catch (error) {
 571→        usedFallback = true;
 572→        console.warn('universe viewport RPC unavailable, using fallback query:', error?.message || error);
 573→    }
 574→
 575→    if(usedFallback){
 576→        posts = await loadUniversePostsFallback(parsedMinX, parsedMaxX, parsedMinY, parsedMaxY, parsedLimit);
 577→    }
 578→
 579→    const postIds = Array.from(new Set(posts.map((post) => post?.id).filter(Boolean)));
 580→    const visibleUserIds = Array.from(new Set(
 581→        posts
 582→            .map((post) => post?.users?.id ?? post?.user_id)
 583→            .filter(Boolean)
 584→    ));
 585→
 586→    const [centroids, edges, similarPairs, starPulls] = await Promise.all([
 587→        getUniverseCentroids(visibleUserIds),
 588→        getUniverseEdges(visibleUserIds),
 589→        getUniverseSimilarPairs(postIds),
 590→        getUniverseStarPulls(postIds)
 591→    ]);
 592→
 593→    return {
 594→        data: posts,
 595→        centroids: centroids,
 596→        edges: edges,
 597→        similarPairs: similarPairs,
 598→        starPulls: starPulls
 599→    };
 600→}
