1222→    const {data: bookMarksData, error: errorBookmarks, count} = await query;
1223→
1224→    if(errorBookmarks){
1225→        console.error('supabase error:', errorBookmarks.message);
1226→        throw {status: 500, error: 'supabase error while fetching bookmarks'}
1227→    }
1228→
1229→    const journalIds = bookMarksData?.map((bookmark) => bookmark.journals.id);
1230→
1231→    if(journalIds.length === 0){
1232→        return {data: [], hasMore: false}
1233→    }
1234→
1235→    let hasLikedPromise;
1236→    let hasBookmarkedPromise;
1237→
1238→    if(journalIds){
1239→        hasLikedPromise = supabase
1240→        .from('likes')
1241→        .select('journal_id')
1242→        .in('journal_id', journalIds)
1243→        .eq('user_id', userId)
1244→
1245→        hasBookmarkedPromise = supabase
1246→        .from('bookmarks')
1247→        .select('journal_id')
1248→        .in('journal_id', journalIds)
1249→        .eq('user_id', userId)
1250→    }
1251→
1252→    const [hasLiked, hasBookMarked] = await Promise.all([
1253→        hasLikedPromise, hasBookmarkedPromise
1254→    ])
1255→
1256→    const {data: hasLikedResult, error: errorHasLikedResult} = hasLiked;
1257→    const {data: hasBookMarkedResult, error: errorHasbookmarkedResult} = hasBookMarked;
1258→
1259→    if(errorHasLikedResult || errorHasbookmarkedResult){
1260→        console.error('supabase error while fetching data:', errorHasLikedResult.message || errorHasbookmarkedResult.message);
1261→        throw {status: 500, error: 'supabase error while fetching data'};
1262→    }
1263→    
1264→    const userHasLikedSet = new Set(hasLikedResult.map((journal) => journal.journal_id) || []);
1265→    const userHasBookmarkedSet = new Set(hasBookMarkedResult.map((bookmark) => bookmark.journal_id) || []);
1266→
1267→    const hasMore = bookMarksData.length > paresedLimit;
1268→
1269→
1270→    const formattedData = bookMarksData.map((b) => ({
1271→        ...b,
1272→        has_liked: userHasLikedSet.has(b.journals.id),
1273→        has_bookmarked: userHasBookmarkedSet.has(b.journals.id),
1274→    }))
1275→
1276→    const slicedData = hasMore ? formattedData.splice(0, paresedLimit) : formattedData;
1277→
1278→    return {
1279→        bookmarks: slicedData,
1280→        hasMore: hasMore,
1281→        totalBookmarks: before ? null : count
1282→    }
1283→}
