1285→export const searchJournalsService = async(query, limit, userId) => {
1286→    const normalizedQuery = normalizeSearchQuery(query);
1287→    if(!normalizedQuery || normalizedQuery.length < SEARCH_QUERY_MIN_LENGTH){
1288→        throw {status: 400, error: `query should be at least ${SEARCH_QUERY_MIN_LENGTH} characters`};
1289→    }
1290→
1291→    if(isNaN(limit) || limit < 1 || limit > SEARCH_LIMIT_MAX){
1292→        throw {status: 400, error: `limit should be an integer between 1 and ${SEARCH_LIMIT_MAX}`};
1293→    }
1294→
1295→    const parsedLimit = parseInt(limit);
1296→    const fetchLimit = Math.min(parsedLimit * 3, 60);
1297→
1298→    const selectColumns = `
1299→        *,
1300→        users(*),
1301→        like_count: likes(count),
1302→        comment_count: comments(count),
1303→        bookmark_count: bookmarks(count)
1304→    `;
1305→
1306→    // Prefer semantic retrieval. If pgvector RPC is unavailable or errors,
1307→    // fallback to keyword search so endpoint still returns useful data.
1308→    try {
1309→        const queryEmbedding = await GenerateEmbeddings(normalizedQuery, '');
1310→
1311→        if(Array.isArray(queryEmbedding) && queryEmbedding.length > 0){
1312→            const {data: matches, error: matchError} = await supabase.rpc('match_public_journals', {
1313→                query_embedding: queryEmbedding,
1314→                match_count: fetchLimit,
1315→                similarity_threshold: 0.35
1316→            });
1317→
1318→            if(matchError){
1319→                console.error('semantic search rpc error:', matchError.message);
1320→            } else if(Array.isArray(matches) && matches.length > 0){
1321→                const matchIds = matches.map((row) => row.id);
1322→                const similarityMap = new Map(matches.map((row) => [row.id, row.similarity]));
1323→
1324→                const {data: journals, error: errorJournals} = await supabase
1325→                    .from('journals')
1326→                    .select(selectColumns)
1327→                    .in('id', matchIds)
1328→                    .eq('privacy', 'public');
1329→
1330→                if(errorJournals){
1331→                    console.error('supabase error while fetching semantic search journals:', errorJournals.message);
1332→                    throw {status: 500, error: 'supabase error while fetching semantic search journals'};
1333→                }
1334→
1335→                const journalById = new Map((journals || []).map((journal) => [journal.id, journal]));
1336→                const orderedSemantic = matchIds
1337→                    .map((id) => journalById.get(id))
1338→                    .filter(Boolean)
1339→                    .map((journal) => ({
1340→                        ...journal,
1341→                        similarity: similarityMap.get(journal.id) || null
1342→                    }));
1343→
1344→                const withInteraction = await attachUserInteractionFlags(orderedSemantic, userId);
1345→                const hasMore = withInteraction.length > parsedLimit;
1346→
1347→                return {
1348→                    data: hasMore ? withInteraction.slice(0, parsedLimit) : withInteraction,
1349→                    hasMore: hasMore,
1350→                    mode: 'semantic'
1351→                };
1352→            }
1353→        }
1354→    } catch (error) {
1355→        console.error('semantic embedding/search fallback error:', error?.message || error);
1356→    }
1357→
1358→    const escapedQuery = normalizedQuery.replace(/[%_]/g, (match) => `\\${match}`);
1359→
1360→    const [titleResult, contentResult] = await Promise.all([
1361→        supabase
1362→            .from('journals')
1363→            .select(selectColumns)
1364→            .eq('privacy', 'public')
1365→            .ilike('title', `%${escapedQuery}%`)
1366→            .order('created_at', {ascending: false})
1367→            .order('id', {ascending: false})
1368→            .limit(parsedLimit + 1),
1369→        supabase
1370→            .from('journals')
1371→            .select(selectColumns)
1372→            .eq('privacy', 'public')
1373→            .ilike('content', `%${escapedQuery}%`)
1374→            .order('created_at', {ascending: false})
1375→            .order('id', {ascending: false})
1376→            .limit(parsedLimit + 1)
1377→    ]);
1378→
1379→    if(titleResult.error || contentResult.error){
1380→        console.error('keyword search error:', titleResult.error?.message || contentResult.error?.message);
1381→        throw {status: 500, error: 'supabase error while searching journals'};
1382→    }
1383→
1384→    const keywordMap = new Map();
1385→    (titleResult.data || []).forEach((journal) => {
1386→        keywordMap.set(journal.id, journal);
1387→    });
1388→    (contentResult.data || []).forEach((journal) => {
1389→        if(!keywordMap.has(journal.id)){
1390→            keywordMap.set(journal.id, journal);
1391→        }
1392→    });
1393→
1394→    const keywordJournals = [...keywordMap.values()];
1395→
1396→    const withInteraction = await attachUserInteractionFlags(keywordJournals || [], userId);
1397→    const hasMore = withInteraction.length > parsedLimit;
1398→
1399→    return {
1400→        data: hasMore ? withInteraction.slice(0, parsedLimit) : withInteraction,
1401→        hasMore: hasMore,
1402→        mode: 'keyword'
1403→    };
1404→}
